module.render:
    const author = args.author || '';
    const contentStr = sections[0] ? sections[0].trim() : '';
    return `\n\n
<div class="mdp-mod-quote">
<div class="mdp-quote-icon">“</div>
<div class="mdp-quote-content">

${contentStr}

</div>
${author ? `<div class="mdp-quote-author">— ${author}</div>` : ''}
</div>
\n\n`;
